import csv
import sys

# Remove duplicate rows from a CSV, keeping the first occurrence.

def dedupe(path):
    seen = set()
    rows = []
    with open(path, newline='') as f:
        for row in csv.reader(f):
            key = tuple(row)
            if key not in seen:
                seen.add(key)
                rows.append(row)
    return rows

if __name__ == '__main__':
    for row in dedupe(sys.argv[1]):
        print(','.join(row))
